import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { UserDTO } from '../../../core/models/user.model';

@Component({
  selector: 'app-header',
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.scss']
})
export class HeaderComponent implements OnInit {
  currentUser: UserDTO | null = null;
  isMobileMenuOpen = false;
  hoverState = false;

  constructor(
    private authService: AuthService,
    public router: Router
  ) {}

  ngOnInit(): void {
    console.log('Header - Initializing');
    this.authService.currentUser$.subscribe(user => {
      this.currentUser = user;
      console.log('Header - User updated:', user);
      console.log('Header - Current user after update:', this.currentUser);
    });

    // Debug: check if there's a token
    console.log('Header - Has token:', this.authService.hasToken());
    console.log('Header - Token:', this.authService.getToken());
  }

  toggleMobileMenu(): void {
    this.isMobileMenuOpen = !this.isMobileMenuOpen;
  }

  logout(): void {
    this.authService.logout().subscribe({
      complete: () => {
        this.authService.clearAuth();
        this.router.navigate(['/auth/login']);
        this.isMobileMenuOpen = false;
      }
    });
  }

  navigateTo(route: string): void {
    this.router.navigate([route]);
    this.isMobileMenuOpen = false;
  }
}
<header class="header">
  <nav class="navbar">
    <div class="navbar-brand">
      <a href="/dashboard" class="logo">
        <span class="logo-text">HackHub</span>
      </a>
    </div>

    <div class="navbar-menu" [class.mobile-menu-open]="isMobileMenuOpen">
      <div class="navbar-start">
        <a class="nav-link" (click)="navigateTo('/dashboard')" [class.active]="router.url === '/dashboard'">
          Dashboard
        </a>
        <a class="nav-link" (click)="navigateTo('/hackathons')" [class.active]="router.url.includes('/hackathons')">
          Hackathons
        </a>
        <a class="nav-link" (click)="navigateTo('/teams')" [class.active]="router.url.includes('/teams')">
          Teams
        </a>
      </div>

      <div class="navbar-end">
        <div class="user-menu" *ngIf="currentUser; else guestMenu">
          <div class="user-info">
            <div class="avatar-placeholder">
              {{ currentUser.nome.charAt(0) }}{{ currentUser.cognome.charAt(0) }}
            </div>
            <div class="user-details">
              <div class="user-name">{{ currentUser.nome }} {{ currentUser.cognome }}</div>
              <div class="user-role">{{ currentUser.ruolo }}</div>
            </div>
          </div>
          <button class="logout-btn" (click)="logout()">
            <span class="logout-text">Logout</span>
          </button>
        </div>

        <ng-template #guestMenu>
          <div class="auth-links">
            <button class="btn-secondary" (click)="navigateTo('/auth/login')">Login</button>
            <button class="btn-primary" (click)="navigateTo('/auth/register')">Register</button>
          </div>
        </ng-template>
      </div>
    </div>

    <button class="mobile-menu-toggle" (click)="toggleMobileMenu()">
      <span></span>
      <span></span>
      <span></span>
    </button>
  </nav>
</header>
